def main(messages) -> dict:
    import ast
    import json

    try:
        parsed_data = None

        if isinstance(messages, list):
            parsed_data = messages

        elif isinstance(messages, str):
            clean_msg = messages.strip()
            try:
                parsed_data = ast.literal_eval(clean_msg)
            except:
                parsed_data = json.loads(clean_msg)

        if isinstance(parsed_data, list):
            return {
                "result": parsed_data[-2:]
            }

    except Exception as e:
        return {
            "result": messages
        }
